# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

from kafka import AdminClient
from kafka.errors import TopicAlreadyExistsError
import argparse

# Parse command-line arguments
parser = argparse.ArgumentParser(description='Kafka topic management')
parser.add_argument('topic_name', help='Name of the topic to create')
parser.add_argument('--partitions', type=int, default=1, help='Number of partitions for the topic')
parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor for the topic')

args = parser.parse_args()

# Create Kafka AdminClient
admin_client = AdminClient({'bootstrap.servers': 'localhost:9092'})

# Create topic
try:
    admin_client.create_topics([
        {'name': args.topic_name, 'num_partitions': args.partitions, 'replication_factor': args.replication_factor}
    ])
    print(f'Topic "{args.topic_name}" created successfully.')
except TopicAlreadyExistsError:
    print(f'Topic "{args.topic_name}" already exists.')

# Close Kafka AdminClient
admin_client.close()